mapper.select:
SELECT IFNULL(AVG(rating), 0) AS averageRating
FROM review
WHERE program_id = #{programId}

SELECT r.review_id, p.program_id, p.title, r.content, r.rating, r.created_at, u.name FROM review r JOIN program p ON r.program_id = p.program_id JOIN workshop w ON p.workshop_id = w.workshop_id JOIN user u ON r.user_id = u.user_id
p.program_id = #{programId}
w.workshop_id = #{workshopId}

mapper.update:
UPDATE review
SET review_image =#{reviewImage}
WHERE review_id = #{reviewId}

mapper.select:
SELECT COUNT(*)
FROM review
WHERE program_id = #{programId}
AND reservation_id = #{reservationId}
AND user_id = #{userId};
